*, *::before, *::after {
    box-sizing: border-box;
    font-family: 'Veranda', 'Gill Sans MT', Calibri, 'Trebuchet MS', sans-serif;
}

body {
	margin: 0;
 	background-color: rgb(229, 229, 229)
}

/* Styling for the top header */
.top-header{
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    background-color: rgba(0, 47, 155);
    margin: 0 15rem 0 15rem;
    height: 10rem;
}

#options{
    margin: .5rem 2rem 0.5rem 1rem;
    border-radius: .3rem;
}

.search-bar{
    display: flex;
    align-items: flex-end;
    flex-direction: row;
    width: 100%;
    margin: .5rem 2rem 0.5rem 1rem;
}

.search-input{
    border-radius: .3rem;
    width: 100%;
    height: 30px;
}

#search-select{
    border-radius: .3rem;
    width: 5rem;
    height: 25px;
    margin: 0 .2rem;
}

.search-btn{
    height: 25px;
    margin: 0 .2rem;
}

.search-btn{
    border: 1px solid #777;
    background-color: #f8f8f8;
    border-radius: .3rem;
    cursor: pointer;
}

.powered-by-google{
    max-height: 30px;
}

/* Styling for the Bottom Header */
.bottom-header{
    display: flex;
    justify-content: space-around;
    align-items: center;
    background-color: rgba(99, 152, 203);
    margin: 0 15rem 0 15rem;
    padding: 0.1rem 3rem 0.1rem 3rem;
    height: 1.75rem;
}

.banner-buttons{
    text-decoration: none;
    color: #f8f8f8;
    font-size: 1rem;
}

/* Styling for the actual page. */
.profile{
    display: flex;
    align-items: center;
    background-color: rgb(255, 255, 255);
    margin: 0 15rem 0 15rem;
    padding: 1rem 3rem 1rem 3rem;
    height: 100%;
}

.slimeball{
    height: 300px;
}

/* Styling for Page Footer*/
.footer{
	margin-bottom: .375rem;
	margin-top: .375rem;
	text-align: center;
	color: #000000;
	font-size: 0.75rem;
	padding: 0 .0625rem .0625rem .3125rem;
}
